const { exec } = require('child_process');

function resizeImage(inputFile, outputFile, dimensions, effects) {
  let effectsCommands = {
    grayscale: '-colorspace Gray',
    sepia: '-sepia-tone 80%',
    blur: '-blur 0x8',
    enhance: '-enhance'
  };

  let effectsApplied = effects
    .filter(effect => effectsCommands.hasOwnProperty(effect))
    .map(effect => effectsCommands[effect])
    .join(' ');

  let command = `gm convert ${inputFile} -resize ${dimensions} ${effectsApplied} ${outputFile}`;

  exec(command, (error, stdout, stderr) => {
    if (error) {
      console.error(`Error: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`Stderr: ${stderr}`);
      return;
    }
    console.log(`Image resized successfully: ${stdout}`);
  });
}